import { Component, Input, Output, EventEmitter } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import * as dayjs from 'dayjs';

interface Calendar {
  id: number;
  name: string;
  color: string;
  url?: string;
  userId: number;
  isActive: boolean;
  syncToken?: string;
  createdAt: string;
  updatedAt: string;
}

interface Event {
  id: string;
  uid?: string;
  title: string;
  description?: string;
  location?: string;
  start_time: string;
  end_time: string;
  all_day: boolean;
  calendar_id: number;
  reminder?: {
    enabled: boolean;
    type: string;
    time: number;
    unit: string;
    relativeTo: string;
  };
  valarm?: {
    trigger: string;
    action: string;
    description: string;
  };
}

@Component({
  selector: 'app-event-detail-modal',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './event-detail-modal.component.html',
  styleUrls: ['./event-detail-modal.component.scss']
})
export class EventDetailModalComponent {
  @Input() event: Event | null = null;
  @Input() calendars: Calendar[] = [];
  @Input() isVisible: boolean = false;
  
  @Output() closeModal = new EventEmitter<void>();
  @Output() editEvent = new EventEmitter<Event>();
  @Output() deleteEvent = new EventEmitter<Event>();

  isEditMode: boolean = false;
  editedEvent: Event | null = null;

  ngOnChanges(): void {
    if (this.event) {
      // Create a copy of the event for editing
      this.editedEvent = { ...this.event };
    }
  }

  getEventCalendar(): Calendar | undefined {
    if (!this.event) return undefined;
    return this.calendars.find(cal => cal.id === this.event!.calendar_id);
  }

  formatDateTime(dateTime: string): string {
    return dayjs(dateTime).format('DD MMMM YYYY HH:mm');
  }

  onClose(): void {
    this.closeModal.emit();
  }

  onEdit(): void {
    if (this.event) {
      this.editEvent.emit(this.event);
    }
  }

  onDelete(): void {
    if (this.event) {
      if (confirm('Are you sure you want to delete this event?')) {
        this.deleteEvent.emit(this.event);
      }
    }
  }
}
<div *ngIf="isVisible && event" class="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50">
  <div class="bg-white rounded-lg shadow-xl max-w-md w-full mx-4 max-h-[90vh] overflow-y-auto">
    <!-- Header -->
    <div class="flex justify-between items-center p-6 border-b border-gray-200">
      <h2 class="text-xl font-semibold text-gray-900">
        {{ isEditMode ? 'Edit Event' : event.title }}
      </h2>
      <button 
        (click)="onClose()"
        class="text-gray-400 hover:text-gray-600 text-2xl font-bold leading-none"
      >
        ×
      </button>
    </div>

    <!-- Content -->
    <div class="p-6">
      <!-- Edit Mode Form -->
      <div *ngIf="isEditMode && editedEvent" class="space-y-4">
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">Title</label>
          <input
            type="text"
            [(ngModel)]="editedEvent.title"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="Event title"
          />
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">Description</label>
          <textarea
            [(ngModel)]="editedEvent.description"
            rows="3"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="Event description"
          ></textarea>
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-1">Location</label>
          <input
            type="text"
            [(ngModel)]="editedEvent.location"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            placeholder="Event location"
          />
        </div>

        <div class="grid grid-cols-2 gap-4">
          <div>
            <label class="block text-sm font-medium text-gray-700 mb-1">Start Date</label>
            <input
              type="datetime-local"
              [value]="editedEvent.start_time.slice(0, 16)"
              (change)="editedEvent.start_time = $event.target.value + ':00'"
              class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
          <div>
            <label class="block text-sm font-medium text-gray-700 mb-1">End Date</label>
            <input
              type="datetime-local"
              [value]="editedEvent.end_time.slice(0, 16)"
              (change)="editedEvent.end_time = $event.target.value + ':00'"
              class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-blue-500"
            />
          </div>
        </div>

        <div>
          <label class="flex items-center">
            <input
              type="checkbox"
              [(ngModel)]="editedEvent.all_day"
              class="mr-2"
            />
            <span class="text-sm font-medium text-gray-700">All Day Event</span>
          </label>
        </div>
      </div>

      <!-- View Mode Content -->
      <div *ngIf="!isEditMode">
        <!-- General Section -->
        <div class="mb-6">
          <h3 class="text-lg font-medium text-gray-900 mb-4">General</h3>
          <div class="space-y-3">
            <div>
              <label class="block text-sm font-medium text-gray-700">Title</label>
              <p class="mt-1 text-sm text-gray-900">{{ event.title }}</p>
            </div>
            
            <div>
              <label class="block text-sm font-medium text-gray-700">Calendar</label>
              <p class="mt-1 text-sm text-gray-900">{{ getEventCalendar()?.name || 'Unknown' }}</p>
            </div>
            
            <div>
              <label class="block text-sm font-medium text-gray-700">Start Date</label>
              <p class="mt-1 text-sm text-gray-900">{{ formatDateTime(event.start_time) }}</p>
            </div>
            
            <div>
              <label class="block text-sm font-medium text-gray-700">End Date</label>
              <p class="mt-1 text-sm text-gray-900">{{ formatDateTime(event.end_time) }}</p>
            </div>
            
            <div *ngIf="event.all_day">
              <label class="block text-sm font-medium text-gray-700">All Day</label>
              <p class="mt-1 text-sm text-gray-900">Yes</p>
            </div>
          </div>
        </div>

        <!-- Description Section -->
        <div *ngIf="event.description" class="mb-6">
          <h3 class="text-lg font-medium text-gray-900 mb-4">Description</h3>
          <div class="bg-gray-50 p-4 rounded-md">
            <p class="text-sm text-gray-900 whitespace-pre-wrap">{{ event.description }}</p>
          </div>
        </div>

        <!-- Location Section -->
        <div *ngIf="event.location" class="mb-6">
          <h3 class="text-lg font-medium text-gray-900 mb-4">Location</h3>
          <p class="text-sm text-gray-900">{{ event.location }}</p>
        </div>
      </div>
    </div>

    <!-- Footer -->
    <div class="flex justify-end space-x-3 p-6 border-t border-gray-200">
      <!-- Edit Mode Buttons -->
      <div *ngIf="isEditMode" class="flex space-x-3">
        <button
          (click)="onCancel()"
          class="px-4 py-2 text-sm font-medium text-gray-700 bg-gray-100 border border-gray-300 rounded-md hover:bg-gray-200 focus:outline-none focus:ring-2 focus:ring-gray-500"
        >
          Cancel
        </button>
        <button
          (click)="onSave()"
          class="px-4 py-2 text-sm font-medium text-white bg-blue-600 border border-transparent rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          Save
        </button>
      </div>

      <!-- View Mode Buttons -->
      <div *ngIf="!isEditMode" class="flex space-x-3">
        <button
          (click)="onDelete()"
          class="px-4 py-2 text-sm font-medium text-red-700 bg-red-100 border border-red-300 rounded-md hover:bg-red-200 focus:outline-none focus:ring-2 focus:ring-red-500"
        >
          Delete
        </button>
        <button
          (click)="onEdit()"
          class="px-4 py-2 text-sm font-medium text-white bg-blue-600 border border-transparent rounded-md hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500"
        >
          Edit
        </button>
      </div>
    </div>
  </div>
</div>
